import React, { useEffect, useState } from 'react'; 
import axios from 'axios'; 
 
const Home = () => { 
    const [songs, setSongs] = useState([]); 
    const [currentSong, setCurrentSong] = useState(null); 
 
    useEffect(() => { 
        const fetchSongs = async () => { 
            try { 
                const res = await axios.get('http://localhost:5000/api/songs'); 
                setSongs(res.data); 
            } catch (err) { console.error(err); } 
        }; 
        fetchSongs(); 
    }, []); 
 
    return ( 
        <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}> 
            <h2 style={{ textAlign: 'center' }}>DANH SACH BAI HAT</h2> 
            <div style={{ display: 'grid', gap: '15px' }}> 
                {songs.map((song) => ( 
                    <div key={song._id} style={{ display: 'flex', alignItems: 'center', padding: '10px', border: '1px solid #ddd', borderRadius: '8px', background: currentSong?._id === song._id ? '#e3f2fd' : '#fff' }}> 
                        <img src={song.imageUrl ? 'http://localhost:5000' + song.imageUrl : 'https://via.placeholder.com/50'} style={{ width: '50px', height: '50px', marginRight: '15px', borderRadius: '4px' }} /> 
                        <div style={{ flex: 1 }}> 
                            <div style={{ fontWeight: 'bold' }}>{song.title}</div> 
                            <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div> 
                        </div> 
                        <button onClick={() => setCurrentSong(song)} style={{ padding: '8px 15px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>PLAY</button> 
                    </div> 
                ))}> 
            </div> 
            {currentSong && ( 
                <div style={{ position: 'fixed', bottom: 0, left: 0, right: 0, background: '#333', color: '#fff', padding: '15px', textAlign: 'center' }}> 
                    <p>Dang phat: <b>{currentSong.title}</b></p> 
                    <audio src={'http://localhost:5000' + currentSong.songUrl} controls autoPlay style={{ width: '100%' }} /> 
                </div> 
            )} 
        </div> 
    ); 
}; 
export default Home;
